/* ── SHARED COMPONENTS ── */
function useReveal() {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const ob = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVis(true); ob.unobserve(e.target); } }, { threshold: 0.08 });
    if (ref.current) ob.observe(ref.current);
    return () => ob.disconnect();
  }, []);
  return [ref, vis];
}

function Reveal({ children, delay = 0, style = {} }) {
  const [ref, vis] = useReveal();
  return <div ref={ref} style={{ opacity: vis ? 1 : 0, transform: vis ? "none" : "translateY(24px)", transition: `opacity .7s cubic-bezier(.16,1,.3,1) ${delay}s, transform .7s cubic-bezier(.16,1,.3,1) ${delay}s`, ...style }}>{children}</div>;
}

function Popup({ open, onClose, children, style: s = {} }) {
  if (!open) return null;
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }} onClick={onClose}>
      <div style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,.5)", backdropFilter: "blur(8px)", WebkitBackdropFilter: "blur(8px)" }} />
      <div style={{ position: "relative", background: "#fff", borderRadius: 20, padding: "40px 36px", maxWidth: 560, width: "100%", maxHeight: "85vh", overflow: "auto", boxShadow: "0 24px 80px rgba(0,0,0,.18)", ...s }} onClick={e => e.stopPropagation()}>
        <button onClick={onClose} style={{ position: "absolute", top: 16, right: 16, background: g.bg, border: "none", borderRadius: "50%", width: 32, height: 32, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16, color: g.t3 }}>✕</button>
        {children}
      </div>
    </div>
  );
}

function Btn({ children, onClick, variant = "primary", style: s = {} }) {
  const base = { padding: "13px 32px", fontSize: 15, fontWeight: 600, borderRadius: 980, cursor: "pointer", fontFamily: ff, transition: "all .35s", letterSpacing: ".03em", textTransform: "uppercase", display: "inline-flex", alignItems: "center", gap: 6 };
  const v = {
    primary: { ...base, background: TEAL, color: "#fff", border: "none" },
    secondary: { ...base, background: "none", color: g.t1, border: "1.5px solid " + g.bdr },
    gold: { ...base, background: GOLD, color: "#fff", border: "none" },
    red: { ...base, background: RED, color: "#fff", border: "none" }
  };
  return <button onClick={onClick} style={{ ...v[variant] || v.primary, ...s }}>{children}</button>;
}

/* ── Hash Router ── */
function useHashRouter() {
  const [page, setPage] = useState(window.location.hash.replace("#/","") || "");
  useEffect(() => {
    const h = () => setPage(window.location.hash.replace("#/","") || "");
    window.addEventListener("hashchange", h);
    return () => window.removeEventListener("hashchange", h);
  }, []);
  const navigate = useCallback((p) => { window.location.hash = "#/" + p; window.scrollTo(0, 0); }, []);
  return { page, navigate };
}

