/* ── Culture Expand Panel ── */
function CultureExpandPanel({ role, onClose, onNavigate }) {
  if (!role) return null;
  const r = CULTURE_ROLES.find(x => x.id === role);
  if (!r) return null;
  return (
    <div style={{ background: g.bg, border: "1px solid " + g.bdr, borderRadius: 16, padding: "36px 32px", marginTop: 24 }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 40 }}>
        <div>
          <button onClick={onClose} style={{ position: "relative", float: "right", background: "none", border: "none", fontSize: 18, cursor: "pointer", color: g.t3 }}>✕</button>
          <div style={{ ...eyebrow, color: TEAL }}>{r.icon} {r.name} · {r.tag}</div>
          <h3 style={{ ...hXl, marginBottom: 14 }}>{r.name} carries the movement.</h3>
          <p style={{ ...bodyMd, marginBottom: 16 }}>{r.brief}</p>
        </div>
        <div>
          <div style={{ background: "#fff", border: "1px solid " + g.bdr, borderRadius: 12, padding: "24px 20px" }}>
            <div style={{ ...eyebrow, marginBottom: 8 }}>The Ask</div>
            <h4 style={{ fontSize: 20, fontWeight: 600, color: g.t1, marginBottom: 12, whiteSpace: "pre-line" }}>{CULTURE_ROLES_ASK.askTitle}</h4>
            <p style={{ ...bodySm, marginBottom: 16 }}>We are inviting a founding group to help give this movement its voice.</p>
            <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 16 }}>
              {CULTURE_ROLES_ASK.steps.map((s, i) => (
                <div key={i} style={{ display: "flex", gap: 10, alignItems: "flex-start", fontSize: 12, color: g.t2 }}>
                  <span style={{ fontFamily: serif, fontSize: 22, fontWeight: 300, color: g.t4, width: 24, flexShrink: 0, lineHeight: "1.2" }}>{i + 1}</span>
                  <span>{s}</span>
                </div>
              ))}
            </div>
            <Btn onClick={() => onNavigate("challenge")} style={{ width: "100%", justifyContent: "center" }}>Join the Challenge →</Btn>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── Alliance Expand Panel ── */
function AllianceExpandPanel({ alliance, onClose, onNavigate }) {
  if (!alliance) return null;
  const a = ALLIANCE_DATA.find(x => x.id === alliance);
  if (!a) return null;
  return (
    <div style={{ background: g.bg, border: "1px solid " + g.bdr, borderRadius: 16, padding: "36px 32px", marginTop: 24 }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 40 }}>
        <div>
          <button onClick={onClose} style={{ float: "right", background: "none", border: "none", fontSize: 18, cursor: "pointer", color: g.t3 }}>✕</button>
          <div style={{ ...eyebrowGold }}>{a.code}</div>
          <h3 style={{ ...hXl, color: g.t1, marginBottom: 8 }}>{a.name}</h3>
          <p style={{ fontFamily: serif, fontSize: 18, color: g.t3, marginBottom: 14, lineHeight: 1.4 }}>{a.line}</p>
          <p style={{ ...bodyMd, marginBottom: 12 }}>{a.brief}</p>
          <p style={{ fontSize: 11, color: g.t4, lineHeight: 1.7 }}>{a.who}</p>
        </div>
        <div>
          <div style={{ ...eyebrow, fontSize: 10, color: g.t4, marginBottom: 12 }}>What alliance partners do</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 20 }}>
            {a.what.map((w, i) => <div key={i} style={{ fontSize: 13, color: g.t2, lineHeight: 1.6, paddingLeft: 16, borderLeft: "2px solid " + TEAL + "40" }}>{w}</div>)}
          </div>
          <div style={{ background: TEAL + "10", border: "1px solid " + TEAL + "30", borderRadius: 8, padding: "14px 16px", marginBottom: 16 }}>
            <p style={{ fontSize: 12, color: g.t2, lineHeight: 1.6 }}><strong>Non-negotiable:</strong> No one encounters the Butterfly Challenge without a clear accessible pathway to real support. Always.</p>
          </div>
          <div style={{ display: "flex", gap: 12 }}>
            <Btn onClick={() => onNavigate("alliances")}>Become a Founding Partner</Btn>
            <Btn variant="secondary" onClick={() => onNavigate("alliances")}>Full Brief →</Btn>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── Nav ── */
function Nav({ page, navigate }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const ease = "cubic-bezier(.16,1,.3,1)";
  const links = [
    { l: "Home", p: "" }, { l: "Challenge", p: "challenge" }, { l: "Culture", p: "culture" },
    { l: "Alliances", p: "alliances" }, { l: "Toolkit", p: "toolkit" }, { l: "Press", p: "press" }
  ];
  const go = (p) => { navigate(p); setMenuOpen(false); };
  const isActive = (p) => page === p || (page === "" && p === "");
  return (
    <>
      <style>{`
        @media(min-width:769px){.nav-mob{display:none!important}.nav-desk{display:flex!important}}
        @media(max-width:768px){.nav-mob{display:flex!important}.nav-desk{display:none!important}}
      `}</style>
      <nav style={{ position: "sticky", top: 0, zIndex: 100, background: "rgba(255,255,255,.92)", backdropFilter: "blur(20px)", WebkitBackdropFilter: "blur(20px)", borderBottom: "1px solid rgba(0,0,0,.06)" }}>
        <div style={{ maxWidth: 1200, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 24px" }}>
          <button onClick={() => go("")} style={{ background: "none", border: "none", cursor: "pointer", padding: 0, display: "flex", alignItems: "center" }}>
            <img src={LOGO_DARK} alt="Butterfly Challenge" style={{ height: 32 }} />
          </button>
          <div className="nav-desk" style={{ display: "none", alignItems: "center", gap: 24 }}>
            {links.map(t => (
              <button key={t.p} onClick={() => go(t.p)} style={{ background: "none", border: "none", fontFamily: ff, fontSize: 13, fontWeight: 500, color: isActive(t.p) ? TEAL : g.t2, cursor: "pointer", padding: 0, position: "relative" }}>
                {t.l}
                {isActive(t.p) && <div style={{ position: "absolute", bottom: -8, left: 0, right: 0, height: 2, background: TEAL, borderRadius: 1 }} />}
              </button>
            ))}
          </div>
          <div className="nav-desk" style={{ display: "none", alignItems: "center", gap: 10 }}>
            <Btn variant="secondary" onClick={() => go("support")} style={{ fontSize: 13, padding: "7px 14px" }}>Find Support</Btn>
            <Btn onClick={() => go("challenge")} style={{ fontSize: 13, padding: "8px 18px" }}>Take the Challenge</Btn>
          </div>
          <div className="nav-mob" style={{ display: "none", alignItems: "center", gap: 8 }}>
            <Btn onClick={() => go("challenge")} style={{ padding: "7px 14px", fontSize: 12 }}>Join</Btn>
            <button onClick={() => setMenuOpen(v => !v)} style={{ background: "none", border: "none", cursor: "pointer", padding: 8, display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", width: 36, height: 36 }}>
              <span style={{ display: "block", width: 18, height: 1.5, background: g.t1, borderRadius: 1, transition: `all .35s ${ease}`, transform: menuOpen ? "translateY(3.75px) rotate(45deg)" : "none" }} />
              <span style={{ display: "block", width: 18, height: 1.5, background: g.t1, borderRadius: 1, margin: "3px 0", transition: `all .35s ${ease}`, opacity: menuOpen ? 0 : 1 }} />
              <span style={{ display: "block", width: 18, height: 1.5, background: g.t1, borderRadius: 1, transition: `all .35s ${ease}`, transform: menuOpen ? "translateY(-3.75px) rotate(-45deg)" : "none" }} />
            </button>
          </div>
        </div>
      </nav>
      <div className="nav-mob" style={{ display: "none", position: "fixed", inset: 0, zIndex: 99, background: "rgba(255,255,255,.98)", backdropFilter: "blur(30px)", flexDirection: "column", justifyContent: "center", alignItems: "center", opacity: menuOpen ? 1 : 0, pointerEvents: menuOpen ? "auto" : "none", transition: `opacity .4s ${ease}` }}>
        {links.map((t, i) => (
          <button key={t.p} onClick={() => go(t.p)} style={{ background: "none", border: "none", fontFamily: ff, cursor: "pointer", padding: "18px 0", width: "80%", fontSize: 32, fontWeight: 600, letterSpacing: "-.02em", color: isActive(t.p) ? TEAL : g.t1, borderBottom: i < links.length - 1 ? "1px solid " + g.bdr : "none", opacity: menuOpen ? 1 : 0, transform: menuOpen ? "translateY(0)" : "translateY(20px)", transition: `opacity .4s ${ease} ${(i + 1) * 60}ms, transform .5s ${ease} ${(i + 1) * 60}ms` }}>
            {t.l}
          </button>
        ))}
        <div style={{ marginTop: 40, display: "flex", gap: 12, opacity: menuOpen ? 1 : 0, transition: `opacity .5s ${ease} .4s` }}>
          <Btn variant="red" onClick={() => go("support")} style={{ fontSize: 14 }}>Find Support</Btn>
        </div>
      </div>
    </>
  );
}

