/* ═══════════════════════════════════════════════════════
   MAIN APP
═══════════════════════════════════════════════════════ */
export default function App() {
  const { page, navigate } = useHashRouter();

  const renderPage = () => {
    switch (page) {
      case "challenge": return <ChallengePage navigate={navigate} />;
      case "culture": return <CulturePage navigate={navigate} />;
      case "alliances": return <AlliancesPage navigate={navigate} />;
      case "impact": return <ImpactPage navigate={navigate} />;
      case "support": return <SupportPage navigate={navigate} />;
      case "governance": return <GovernancePage navigate={navigate} />;
      case "toolkit": return <ToolkitPage navigate={navigate} />;
      case "press": return <PressPage navigate={navigate} />;
      default: return <HomePage navigate={navigate} />;
    }
  };

  return (
    <div style={{ fontFamily: ff, color: g.t1 }}>
      <style>{`
        * { margin: 0; padding: 0; box-sizing: border-box; }
        a { color: ${TEAL}; }
        button { transition: all .35s; }
        @media(max-width:768px) {
          .two-col-resp { grid-template-columns: 1fr !important; }
        }
      `}</style>

      <Nav page={page} navigate={navigate} />
      {renderPage()}
      <Footer navigate={navigate} />

      {/* Fixed Support Bar */}
      <div style={{ position: "fixed", bottom: 0, left: 0, right: 0, zIndex: 50, background: "rgba(255,255,255,.92)", backdropFilter: "blur(20px)", WebkitBackdropFilter: "blur(20px)", borderTop: "1px solid rgba(0,0,0,.06)", padding: "7px 16px", display: "flex", alignItems: "center", justifyContent: "center", gap: 16 }}>
        <span style={{ fontSize: 11, color: g.t4, fontFamily: ff }}>Need support?</span>
        <a href="tel:988" style={{ fontSize: 13, fontWeight: 600, color: TEAL, textDecoration: "none", fontFamily: ff }}>988</a>
        <span style={{ fontSize: 11, color: g.bdr }}>·</span>
        <a href="https://findahelpline.com" target="_blank" rel="noopener" style={{ fontSize: 12, fontWeight: 500, color: g.t3, textDecoration: "none", fontFamily: ff }}>findahelpline.com</a>
      </div>
    </div>
  );
}
